module PostsHelper
  # Custom sanitization helper for blog post content
  # This is the SAFE alternative to raw() and html_safe
  ALLOWED_POST_TAGS = %w[
    p br h1 h2 h3 h4 h5 h6
    strong em b i u s strike del
    a img
    ul ol li
    blockquote pre code
    hr div span
    sub sup
    table thead tbody tfoot tr th td
    figure figcaption
    details summary
  ].freeze

  ALLOWED_POST_ATTRIBUTES = %w[
    href src alt title class id
    target rel
    width height
    colspan rowspan
  ].freeze

  def safe_post_content(content)
    sanitize(content, tags: ALLOWED_POST_TAGS, attributes: ALLOWED_POST_ATTRIBUTES)
  end

  ALLOWED_COMMENT_TAGS = %w[p br strong em b i a code].freeze
  ALLOWED_COMMENT_ATTRIBUTES = %w[href target rel].freeze

  def safe_comment_content(content)
    sanitize(content, tags: ALLOWED_COMMENT_TAGS, attributes: ALLOWED_COMMENT_ATTRIBUTES)
  end
end